const fechaActualTexto = $('When Executed by Another Workflow').first().json['Fecha actual'] || null;
const fechaNuevaTexto = $('When Executed by Another Workflow').first().json['Fecha nueva'] || null;

const duracionMinutos = Number($input.first().json.Tiempo_estimado_min || 0);

function calcularFechaFin(fechaTexto, duracion) {
  if (!fechaTexto) return null;
  const fecha = new Date(fechaTexto);
  fecha.setMinutes(fecha.getMinutes() + duracion);
  return fecha.toISOString().substring(0, 19);
}

function formatearFechaSimple(fechaTexto) {
  if (!fechaTexto) return null;
  const fecha = new Date(fechaTexto);
  const dia = String(fecha.getDate()).padStart(2, '0');
  const mes = String(fecha.getMonth() + 1).padStart(2, '0');
  const anio = fecha.getFullYear();
  return `${dia}/${mes}/${anio}`;
}

function formatearFechaHoraSimple(fechaTexto) {
  if (!fechaTexto) return null;
  const fecha = new Date(fechaTexto);
  const dia = String(fecha.getDate()).padStart(2, '0');
  const mes = String(fecha.getMonth() + 1).padStart(2, '0');
  const anio = fecha.getFullYear();
  const horas = String(fecha.getHours()).padStart(2, '0');
  const minutos = String(fecha.getMinutes()).padStart(2, '0');
  return `${dia}/${mes}/${anio} ${horas}:${minutos}`;
}

return [
  {
    json: {
      "Fecha actual inicio": fechaActualTexto,
      "Fecha actual fin": calcularFechaFin(fechaActualTexto, duracionMinutos),
      "Fecha nueva inicio": fechaNuevaTexto,
      "Fecha nueva fin": calcularFechaFin(fechaNuevaTexto, duracionMinutos),
      "Fecha Nueva Inicio Simple": formatearFechaSimple(fechaNuevaTexto),
      "Fecha Nueva Inicio Simple con Hora": formatearFechaHoraSimple(fechaNuevaTexto),
      "DuracionMinutos": String(duracionMinutos)
    }
  }
];

let summary;
let telefono;

// Obtener datos
try {
  summary = $input.first().json.summary;
} catch {
  summary = undefined;
}

try {
  telefono = $('When Executed by Another Workflow')?.first()?.json?.Telefono;
} catch {
  telefono = undefined;
}


// ----------------------------
// EXTRAER NUMERO
// ----------------------------
function extraerNumero(valor) {

  if (!valor) return null;

  const texto = String(valor);

  // formato whatsapp jid
  let match = texto.match(/(\d+)@s\.whatsapp\.net/);
  if (match) return match[1];

  // numero plano (+54, 549, etc)
  const digits = texto.replace(/\D/g, "");
  if (digits.length >= 8) return digits;

  return null;
}


// ----------------------------
// NUMEROS DETECTADOS
// ----------------------------
const numeroSummary = extraerNumero(summary);
const numeroTelefono = extraerNumero(telefono);


// ----------------------------
// LOGICA FINAL
// ----------------------------

// ✅ Si alguno tiene numero → validar coincidencia
if (numeroSummary !== null || numeroTelefono !== null) {

  if (numeroSummary === null || numeroTelefono === null) {
    return [{ json: { coincide: false } }];
  }

  return [{
    json: {
      coincide: numeroSummary === numeroTelefono
    }
  }];
}

// ✅ Ninguno tiene numero → permitir
return [{
  json: {
    coincide: true
  }
}];

