const input = $('Formatear_input').first().json;
const citaActual = $('traer_cita_actual').first().json;

// Sacar el timezone (-03:00) y parsear solo la parte local
function parseLocal(str) {
  return new Date(str.substring(0, 19));
}

const inicioActual = parseLocal(citaActual.start.dateTime);
const finActual = parseLocal(citaActual.end.dateTime);
const inicioNuevo = parseLocal(input["Fecha nueva inicio"]);
const finNuevo = parseLocal(input["Fecha nueva fin"]);

const checks = [];

function mismoDia(a, b) {
  return (
    a.getFullYear() === b.getFullYear() &&
    a.getMonth() === b.getMonth() &&
    a.getDate() === b.getDate()
  );
}

function format(date) {
  const y = date.getFullYear();
  const m = String(date.getMonth() + 1).padStart(2,'0');
  const d = String(date.getDate()).padStart(2,'0');
  const h = String(date.getHours()).padStart(2,'0');
  const min = String(date.getMinutes()).padStart(2,'0');
  const s = String(date.getSeconds()).padStart(2,'0');
  return `${y}-${m}-${d}T${h}:${min}:${s}`;
}

if (!mismoDia(inicioActual, inicioNuevo)) {
  checks.push({
    desde: format(inicioNuevo),
    hasta: format(finNuevo)
  });
} else {
  if (inicioNuevo < inicioActual) {
    const hasta = new Date(Math.min(finNuevo.getTime(), inicioActual.getTime()));
    if (hasta > inicioNuevo) {
      checks.push({
        desde: format(inicioNuevo),
        hasta: format(hasta)
      });
    }
  }
  if (finNuevo > finActual) {
    const desde = new Date(Math.max(inicioNuevo.getTime(), finActual.getTime()));
    if (finNuevo > desde) {
      checks.push({
        desde: format(desde),
        hasta: format(finNuevo)
      });
    }
  }
}

return [{ checks }];

const intervalos = $json.intervalosDisponibles;
const fecha = $('Formatear_input').first().json['Fecha Nueva Inicio Simple'];

function esManana(hora) {
  const h = parseInt(hora.split(":")[0], 10);
  return h < 13;
}

function esTarde(hora) {
  const h = parseInt(hora.split(":")[0], 10);
  return h >= 13;
}

let manana = [];
let tarde = [];

for (const i of intervalos) {
  if (esManana(i.desde)) {
    manana.push(i);
  } else {
    tarde.push(i);
  }
}

let texto = `No hay disponibilidad para el horario solicitado. Estos son los horarios disponibles para el ${fecha}:\n`;

if (manana.length) {
  texto += `\nPor la mañana:\n`;
  manana.forEach(i => {
    texto += `• Desde ${i.desde} hasta ${i.hasta}\n`;
  });
}

if (tarde.length) {
  texto += `\nPor la tarde:\n`;
  tarde.forEach(i => {
    texto += `• Desde ${i.desde} hasta ${i.hasta}\n`;
  });
}

return [{ texto }];

